import{_ as a,o as t,c as r,R as i}from"./chunks/framework.eDbi1Hhd.js";const u=JSON.parse('{"title":"1.1 JavaScript 简介","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/04.javascript/01.the-javascript-language/01.an-introduction/01.an-introduction-to-javascript.md","filePath":"tutorials/04.javascript/01.the-javascript-language/01.an-introduction/01.an-introduction-to-javascript.md","lastUpdated":1685452959000}'),e={name:"tutorials/04.javascript/01.the-javascript-language/01.an-introduction/01.an-introduction-to-javascript.md"},o=i('<h1 id="_1-1-javascript-简介" tabindex="-1">1.1 JavaScript 简介 <a class="header-anchor" href="#_1-1-javascript-简介" aria-label="Permalink to &quot;1.1 JavaScript 简介&quot;">​</a></h1><h2 id="javascript-引擎" tabindex="-1">JavaScript 引擎 <a class="header-anchor" href="#javascript-引擎" aria-label="Permalink to &quot;JavaScript 引擎&quot;">​</a></h2><p>JavaScript 引擎实际上也是一个程序，它做的事情主要是：读取（又可以称作“解析”）代码、将代码翻译（又可以称作“解析”）成机器码、执行翻译后的机器码。</p><p>V8 是目前最常见的 JavaScript 引擎，以性能著称，包含在 Chrome、新 Edge 等浏览器中。</p><h2 id="javascript-运行时" tabindex="-1">JavaScript 运行时 <a class="header-anchor" href="#javascript-运行时" aria-label="Permalink to &quot;JavaScript 运行时&quot;">​</a></h2><p>运行时就是编程语言执行的环境。JavaScript 运行时自然就是指 JavaScript 执行的环境，它是一个扩展 JavaScript 引擎并提供附加功能的程序。</p><p>浏览器就是一个常见的 JavaScript 运行时，它提供了网络 API（包括操作文档、绘制和操作图形、请求服务器数据等）、回调队列、事件循环等附加功能。</p><p><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> 也是一个常见的 JavaScript 运行时，它提供了不同的附加功能，允许在服务器上运行 JavaScript。我们将在其它教程深入了解学习它。</p><p>我们甚至可以使用别的运行时来构建桌面和移动应用，同样地，我们将在其它教程展开这部分内容。</p><h2 id="javascript-上层-语言" tabindex="-1">JavaScript “上层”语言 <a class="header-anchor" href="#javascript-上层-语言" aria-label="Permalink to &quot;JavaScript “上层”语言&quot;">​</a></h2><p>TypeScript 是目前使用非常广泛也是目前最受欢迎的 JavaScript “上层”语言，在学习完该教程后，我们会立刻开始 TypeScript 语言的学习。</p><h2 id="🙏-致谢" tabindex="-1">🙏 致谢 <a class="header-anchor" href="#🙏-致谢" aria-label="Permalink to &quot;🙏 致谢&quot;">​</a></h2><p>该部分参考了 <a href="https://algodaily.com/lessons/introduction-to-js-engines-and-runtimes" target="_blank" rel="noreferrer">https://algodaily.com/lessons/introduction-to-js-engines-and-runtimes</a>。</p>',13),c=[o];function n(p,s,d,l,h,v){return t(),r("div",null,c)}const S=a(e,[["render",n]]);export{u as __pageData,S as default};
